624→    public ConsumerRecords<K, V> poll(final Duration timeout) {
   625→        return poll(time.timer(timeout));
   626→    }
   627→
   628→    /**
   629→     * @throws KafkaException if the rebalance callback throws exception
   630→     */
   631→    private ConsumerRecords<K, V> poll(final Timer timer) {
   632→        acquireAndEnsureOpen();
   633→        try {
   634→            this.kafkaConsumerMetrics.recordPollStart(timer.currentTimeMs());
   635→
   636→            if (this.subscriptions.hasNoSubscriptionOrUserAssignment()) {
   637→                throw new IllegalStateException("Consumer is not subscribed to any topics or assigned any partitions");
   638→            }
   639→
   640→            do {
   641→                client.maybeTriggerWakeup();
   642→
   643→                // try to update assignment metadata BUT do not need to block on the timer for join group
   644→                updateAssignmentMetadataIfNeeded(timer, false);
   645→
   646→                final Fetch<K, V> fetch = pollForFetches(timer);
   647→                if (!fetch.isEmpty()) {
   648→                    // before returning the fetched records, we can send off the next round of fetches
   649→                    // and avoid block waiting for their responses to enable pipelining while the user
   650→                    // is handling the fetched records.
   651→                    //
   652→                    // NOTE: since the consumed position has already been updated, we must not allow
   653→                    // wakeups or any other errors to be triggered prior to returning the fetched records.
   654→                    if (sendFetches() > 0 || client.hasPendingRequests()) {
   655→                        client.transmitSends();
   656→                    }
   657→
   658→                    if (fetch.records().isEmpty()) {
   659→                        log.trace("Returning empty records from `poll()` "
   660→                                + "since the consumer's position has advanced for at least one topic partition");
   661→                    }
   662→
   663→                    return this.interceptors.onConsume(new ConsumerRecords<>(fetch.records(), fetch.nextOffsets()));
   664→                }
   665→            } while (timer.notExpired());
   666→
   667→            return ConsumerRecords.empty();
   668→        } finally {
   669→            release();
   670→            this.kafkaConsumerMetrics.recordPollEnd(timer.currentTimeMs());
   671→        }
   672→    }
   673→
   674→    private int sendFetches() {
   675→        offsetFetcher.validatePositionsOnMetadataChange();
   676→        return fetcher.sendFetches();
   677→    }
   678→
   679→    boolean updateAssignmentMetadataIfNeeded(final Timer timer, final boolean waitForJoinGroup) {
   680→        if (coordinator != null && !coordinator.poll(timer, waitForJoinGroup)) {
   681→            return false;
   682→        }
   683→
   684→        return updateFetchPositions(timer);
   685→    }
   686→
   687→    /**
   688→     * @throws KafkaException if the rebalance callback throws exception
   689→     */
   690→    private Fetch<K, V> pollForFetches(Timer timer) {
   691→        long pollTimeout = coordinator == null ? timer.remainingMs() :
   692→                Math.min(coordinator.timeToNextPoll(timer.currentTimeMs()), timer.remainingMs());
   693→
   694→        // if data is available already, return it immediately
   695→        final Fetch<K, V> fetch = fetcher.collectFetch();
   696→        if (!fetch.isEmpty()) {
   697→            return fetch;
   698→        }
   699→
   700→        // send any new fetches (won't resend pending fetches)
   701→        sendFetches();
   702→
   703→        // We do not want to be stuck blocking in poll if we are missing some positions
   704→        // since the offset lookup may be backing off after a failure
   705→
   706→        // NOTE: the use of cachedSubscriptionHasAllFetchPositions means we MUST call
   707→        // updateAssignmentMetadataIfNeeded before this method.
   708→        if (!cachedSubscriptionHasAllFetchPositions && pollTimeout > retryBackoffMs) {
   709→            pollTimeout = retryBackoffMs;
   710→        }
   711→
   712→        log.trace("Polling for fetches with timeout {}", pollTimeout);
   713→
   714→        Timer pollTimer = time.timer(pollTimeout);
   715→        client.poll(pollTimer, () -> {
   716→            // since a fetch might be completed by the background thread, we need this poll condition
   717→            // to ensure that we do not block unnecessarily in poll()
   718→            return !fetcher.hasAvailableFetches();
   719→        });
   720→        timer.update(pollTimer.currentTimeMs());
   721→
   722→        return fetcher.collectFetch();
   723→    }

